-- Additional confirmed facts from novels, in-game codex, developer statements, and community discoveries

INSERT INTO confirmed_facts (title, description, source_person, source_type, source_url, source_date, status, sort_order) VALUES

-- THE DARK WHEEL NOVELLA (Robert Holdstock, 1984)
('The Dark Wheel Toast to Raxxla',
 'The novella contains the legendary toast: "To the jewel that burns on the brow of the mother of galaxies! To the whisperer in witchspace, the siren of the deepest void! The parent''s grief, the lover''s woe, and the yearning of our vagabond hearts. To Raxxla!" This toast was later incorporated into the in-game Codex entry, confirming its canonical significance.',
 'Robert Holdstock', 'novel', 'http://www.elitehomepage.org/dkwheel.htm', '1984-09-20', 'confirmed', 100),

('Raxxla contains an alien gateway to other universes',
 'Rafe Zetter tells Alex Ryder: "If it does, then on Raxxla there''s an alien construct that''s a gateway to other Universes, and all that''s in those Universes in the way of bounty, and treasures, and aliens, and life..." This is the primary physical description of what Raxxla contains from the original lore source.',
 'Robert Holdstock', 'novel', 'http://www.elitehomepage.org/dkwheel.htm', '1984-09-20', 'confirmed', 101),

('Raxxla is a ghost world, a planet',
 'When Alex assumes Raxxla is an alien, Rafe corrects him: "Raxxla''s no alien, Alex. It''s a ghost world. A planet. A legend..." This establishes Raxxla as a physical place (a planet), not an entity or concept.',
 'Robert Holdstock', 'novel', 'http://www.elitehomepage.org/dkwheel.htm', '1984-09-20', 'confirmed', 102),

('Jason Ryder found solid evidence of Raxxla',
 'Jason Ryder, an Elite-ranked combateer and the only canonically confirmed member of the Dark Wheel in the novella, told his friend Rafe Zetter he had found solid evidence of Raxxla''s existence. He was assassinated before he could pursue the lead. His last word to his son Alex was "Raxxla."',
 'Robert Holdstock', 'novel', 'http://www.elitehomepage.org/dkwheel.htm', '1984-09-20', 'confirmed', 103),

('Must be Elite to reach Raxxla',
 'Rafe tells Alex: "Unless you get there, unless you become Elite, you''ll never get to Raxxla." And: "But don''t you go worrying about Raxxla. Not yet. That comes in time..." This suggests the path to Raxxla requires achieving Elite status first.',
 'Robert Holdstock', 'novel', 'http://www.elitehomepage.org/dkwheel.htm', '1984-09-20', 'confirmed', 104),

('The Dark Wheel: semi-legendary star riders',
 'The novella describes the Dark Wheel as "a semi-legendary space unit, star-riders who made it their business to seek the truth behind the plethora of myths" in the galaxy. This is the foundational definition of the organization.',
 'Robert Holdstock', 'novel', 'http://www.elitehomepage.org/dkwheel.htm', '1984-09-20', 'confirmed', 105),

('Raxxla allegedly guarded by corrupt Elitists',
 'The novella describes Raxxla as guarded by "a corps of ruthless, power crazed Elitists" who have supposedly found it and are intent on monopolising its power. The assassin who killed Jason Ryder had possible links to this group.',
 'Robert Holdstock', 'novel', 'http://www.elitehomepage.org/dkwheel.htm', '1984-09-20', 'confirmed', 106),

('Raxxla first appeared in 1984 Elite packaging',
 'The Dark Wheel novella was packaged with the original Elite game (1984) and was the first novella in history distributed with a video game. Raxxla and the Dark Wheel are mysteries that have persisted for over 40 years across the entire Elite franchise.',
 'Robert Holdstock', 'novel', NULL, '1984-09-20', 'confirmed', 107),

-- IN-GAME CODEX ENTRIES (Update 3.3, December 2018)
('Raxxla Codex entry references centuries of legend',
 'The in-game Codex contains a full entry on Raxxla. Key passage: "The legend of Raxxla has been circulating, in whispers, for centuries." It notes it is "extremely difficult to find consistency among the various fragmentary rumours" and compares Raxxla to "Atlantis, Eldorado and the kingdom of Prester John."',
 NULL, 'in_game', NULL, '2018-12-11', 'confirmed', 110),

('The Omphalos Rift: alien gateway artifact',
 'The Codex states: "Several versions of the Raxxla story mention an alien artifact: The Omphalos Rift, described as a gateway or tunnel through which parallel universes can be accessed." However, details "were later shown to bear a striking resemblance to the children''s story ''Princess Astrophel and the Spiralling Stars'', and soon lost credibility." Some insisted the author "cunningly concealed facts about the mysterious locale in his book, as hints for those with eyes to see." Omphalos means "navel" or "centre of the world" in Greek.',
 NULL, 'in_game', NULL, '2018-12-11', 'confirmed', 111),

('Raxxla legend causes Fernweh effect',
 'The Codex notes: "Students of Raxxla lore have noted that the legend exerts a strangely potent fascination on the minds of seekers. Commentators have compared this sensation to Fernweh: the unaccountable longing for a place one has never seen. More than one interstellar treasure seeker has become obsessed with Raxxla to the exclusion of all other dreams."',
 NULL, 'in_game', NULL, '2018-12-11', 'confirmed', 112),

('Raxxla Codex references a sinister cabal',
 'The Codex states: "Raxxla also plays a role in several conspiracy theories, most of which attest that it has already been discovered by some kind of sinister cabal or sole-tyrant which has leveraged its power to establish covert dominance over humanity." This mirrors the novella''s corrupt Elitists and echoes themes around The Club.',
 NULL, 'in_game', NULL, '2018-12-11', 'confirmed', 113),

('The Dark Wheel Codex entry',
 'The in-game Codex describes The Dark Wheel as "a legendary group of adventurers, explorers, investigators and treasure-hunters, the existence of which is so lacking in corroborative evidence that it is generally considered a myth." It notes "it is always they who initiate contact, initially in disguise, revealing their true identity only once a suitable test of courage and skill has been discreetly administered, and passed."',
 NULL, 'in_game', NULL, '2018-12-11', 'confirmed', 114),

('Dark Wheel station: toroid orbiting eighth moon',
 'The Codex references theorist Lyta Crane who claims the original Dark Wheel "operated from a disused starport orbiting the eighth moon of an unnamed gas giant." The station "was a toroid, hence ''wheel''" kept on "minimal power output for concealment." However "Crane has her share of critics who have accused her of forging evidence" and the station has never been located.',
 NULL, 'in_game', NULL, '2018-12-11', 'confirmed', 115),

('Earliest Raxxla reference: Art Tornqvist journal, 2296',
 'Per the Codex, the earliest recorded mention of Raxxla dates from 2296, from the journal of Art Tornqvist, a shipboard mechanic based in the Tau Ceti system. Although his account is the first known attestation, it is clear from context that the myth was already in circulation at that time.',
 NULL, 'in_game', NULL, '2018-12-11', 'confirmed', 116),

('Dark Wheel membership may be hereditary',
 'The in-game Codex notes that Dark Wheel members are "sometimes selected by lineage, with existing members training their children before revealing membership" and that "the group''s secrets are dangerous." This aligns with the novella''s portrayal of Jason Ryder preparing his son Alex.',
 NULL, 'in_game', NULL, '2018-12-11', 'confirmed', 117),

-- ADDITIONAL DEVELOPER STATEMENTS
('Braben: "We know where it is"',
 'On July 8, 2014, at the BAFTA Games Showcase in London, Drew Wagar asked David Braben "Is Raxxla in the game?" Braben answered: "Yes, and we know where it is." Wagar confirmed this on Twitter on June 26, 2021.',
 'David Braben', 'developer', 'http://www.drewwagar.com/progress-report/the-day-i-met-david-braben/', '2014-07-08', 'confirmed', 120),

('Brookes: "There will be no clues"',
 'Michael Brookes, Executive Producer of Elite Dangerous, stated regarding Raxxla: "There will be no clues." This is one of the most frequently cited developer statements about the mystery.',
 'Michael Brookes', 'developer', NULL, NULL, 'confirmed', 121),

('Braben: "We know why people haven''t found it"',
 'David Braben stated: "It exists, we know where it is and we know why people haven''t been able to find it..." This implies there is a specific reason or mechanism preventing discovery, not just that nobody has visited the right system.',
 'David Braben', 'developer', NULL, NULL, 'confirmed', 122),

('Brookes: some clues made "a tiny bit obvious"',
 'Despite saying "no clues," Brookes later clarified: "I think you have to make some of it a tiny bit obvious just so people know what they''re doing." This suggests there ARE subtle signposts in the game, appearing to contradict the absolute "no clues" statement.',
 'Michael Brookes', 'developer', NULL, NULL, 'confirmed', 123),

-- AND HERE THE WHEEL (John Harper, 2014)
('The Dark Wheel always led by a Ryder',
 'John Harper''s novel "And Here The Wheel" (2014) establishes that the Dark Wheel was always led by a Ryder and always hunted for Raxxla. Alex Ryder had two sons: Neptune and Oberon. They split over priorities: Oberon believed he could find Soontill, while Neptune considered anything other than Raxxla irrelevant. The disagreement led to a schism.',
 'John Harper', 'novel', NULL, '2014-06-12', 'confirmed', 130),

('Soontill: the Dark Wheel''s other discovery',
 '"And Here The Wheel" reveals the Dark Wheel located a mysterious planet called Soontill, said to contain "Thargoid treasures beyond anyone''s wildest dreams," but they never confirmed finding Raxxla itself. This establishes Soontill as a separate mystery connected to the Dark Wheel lineage.',
 'John Harper', 'novel', NULL, '2014-06-12', 'confirmed', 131),

-- IN-GAME FACTION AND LOCATION DATA
('The Dark Wheel faction in Shinrarta Dezhra',
 'A minor faction calling itself "The Dark Wheel" is present in Shinrarta Dezhra, a permit-locked system (requires any Elite rank to access) that serves as the Pilots Federation headquarters. Some missions from this faction reference "the great mystery." Whether this is the original Dark Wheel or an imitator is left deliberately ambiguous.',
 NULL, 'in_game', NULL, '2014-12-16', 'confirmed', 140),

('Soontill Relics at Cheranovsky City, Ngurii',
 'Soontill Relics are in-game commodity items: slabs of unidentified material covered in pictographs of unknown origin, exclusively sold at Cheranovsky City in the Ngurii system. Analysis confirmed they were not made by human hands and do not conform to known Thargoid materials. Isotopic dating indicates they are tens of thousands of years old.',
 NULL, 'in_game', NULL, '2015', 'confirmed', 141),

-- PROJECT DYNASTY AND THE CLUB
('Project Dynasty: The Club''s contingency plan',
 'The Club organised Project Dynasty to find Earth-like worlds as potential refuges from a Thargoid invasion. Three expeditions were sent: to the Formidine Rift, Hawking''s Gap, and the Scutum-Sagittarii Conflux. Crews were to be eliminated after completing their missions to preserve secrecy.',
 NULL, 'in_game', NULL, '2017-04-29', 'confirmed', 150),

('Zurara megaship found in Formidine Rift',
 'On April 17, 3303, the derelict megaship Zurara was discovered in the Syreadiae JX-F c0 system deep in the Formidine Rift. Sleeper agents among the crew had sabotaged the ship after it completed its mission. Audio logs revealed the crew''s fate.',
 NULL, 'in_game', NULL, '2017-04-17', 'confirmed', 151),

('Teorge listening posts reveal The Club conspiracy',
 'Seven "RAGAZZA" logs were discovered at listening posts in the Teorge system after Salome''s death on April 29, 3303. The author "Rebecca" identifies as a former conspirator with an "attack of conscience." The logs reveal that hidden powers "have known for decades, maybe centuries" of an approaching threat, manufactured wars, and planned "the Exodus, the Dynasty plan."',
 NULL, 'in_game', NULL, '2017-04-29', 'confirmed', 152),

('Salome killed trying to expose The Club',
 'Lady Kahina Tijani Loren (Salome) was killed in the Arumclaw system on April 29, 3303 while attempting to reach Teorge to publicly expose a shadowy cabal (The Club). Despite her death, her co-conspirators survived and revealed the Teorge listening post locations. This was a live in-game event with over 3,000 players.',
 NULL, 'in_game', NULL, '2017-04-29', 'confirmed', 153),

-- PERMIT-LOCKED SYSTEMS
('Unknown permit systems remain inaccessible',
 'Multiple systems and regions require "Unknown Permits" with no known method to obtain access. Notable examples include: the entire Col 70 Sector (near Witch Head Nebula), Polaris, and many others (HIP 51073, HR 4413, LFT 509, LHS 2894, Mingfu, Ross 354, Wolf 262). Permit-locked regions also include Regor Sector, Horsehead Dark Region, and multiple NGC sectors.',
 NULL, 'in_game', NULL, NULL, 'confirmed', 160),

-- CANONICAL STATUS
('Dark Wheel novella canonical status uncertain',
 'Drew Wagar has emphasised that "The Dark Wheel" novella by Holdstock is not considered strict canon for Elite Dangerous, though he suspects it remains "fairly accurate." The Codex entries added in 2018 selectively incorporated elements from the novella while adding new lore, suggesting Frontier treats it as foundational inspiration rather than binding canon.',
 'Drew Wagar', 'developer', NULL, '2015', 'confirmed', 170);
